const mu=rets.reduce((a,b)=>a+b,0)/rets.length;
const sigma=Math.sqrt(rets.reduce((a,r)=>a+Math.pow(r-mu,2),0)/rets.length)||0.01;
const paths=500,steps=24,dt=1;
const finals=[];
for(let p=0;p<paths;p++){
  let S=price;
  for(let t=0;t<steps;t++){
    const u1=Math.random()+1e-10,u2=Math.random();
    const z=Math.sqrt(-2*Math.log(u1))*Math.cos(2*Math.PI*u2);
    S*=Math.exp((mu-0.5*sigma*sigma)*dt+sigma*Math.sqrt(dt)*z);
  }
  finals.push(S);
}
finals.sort((a,b)=>a-b);
const newsSentimentAdj=(news&&news.score||0)/100*0.5;
