  for(let t=0;t<fN;t++){
    re+=fC[t]*Math.cos(2*Math.PI*fr*t);
    im+=fC[t]*Math.sin(2*Math.PI*fr*t);
  }
  const pw=re*re+im*im;
  if(pw>maxP){maxP=pw;domP=per;}
}

