const MAX_RETRIES = 3;
const RETRY_DELAYS = [1000, 3000, 7000]; // ms: 1s, 3s, 7s (exponential backoff)

function getKrakenSignature(urlpath, data) {
  const crypto = require('crypto');
  const dataStr = new URLSearchParams(data).toString();
  const nonce = data.nonce || Math.floor(Date.now() * 1000);
  const message = dataStr + `&nonce=${nonce}`;
  const secretBuffer = Buffer.from(CRYPT_PRIVATE_KEY, 'base64');
  const hash = crypto.createHash('sha256').update(message).digest('binary');
  const hmac = crypto.createHmac('sha512', secretBuffer).update(urlpath + hash, 'binary').digest('base64');
  return hmac;
}

async function submitOrderWithRetry() {
  let lastError = null;

  for (let attempt = 0; attempt < MAX_RETRIES; attempt++) {
    try {
      return await new Promise((resolve, reject) => {
        const orderData = {
          pair: 'XBTUSD',
          type: 'market',
          ordertype: 'market',
          side: signal === 'BUY' ? 'buy' : 'sell',
          volume: tradeSize.toFixed(8),
          nonce: Math.floor(Date.now() * 1000)
        };

        const urlpath = '/0/private/AddOrder';
        const dataStr = new URLSearchParams(orderData).toString();
        const signature = getKrakenSignature(urlpath, orderData);

        const req = https.request({
          hostname: 'api.kraken.com',
          path: urlpath,
          method: 'POST',
          headers: {
            'API-Key': CRYPT_API_KEY,
            'API-Sign': signature,
            'Content-Type': 'application/x-www-form-urlencoded'
          },
          timeout: 10000
        }, (res) => {
          let data = '';
          res.on('data', c => data += c);
          res.on('end', () => {
            try {
              const json = JSON.parse(data);

              if (json.error && json.error.length > 0) {
                const err = json.error[0];
                const isRetryable = err.includes('rate limit') || err.includes('temporarily') || err.includes('unavailable');

                if (isRetryable && attempt < MAX_RETRIES - 1) {
                  reject({ retryable: true, error: err, attempt });
                } else {
                  resolve({ status: 'KRAKEN_ERROR', error: err, attempts: attempt + 1 });
                }
              } else if (json.result?.txid?.[0]) {
                resolve({ status: 'ORDER_SUBMITTED', order_id: json.result.txid[0], attempts: attempt + 1 });
              } else {
                resolve({ status: 'UNKNOWN_RESPONSE', response: json });
              }
            } catch (e) {
              resolve({ status: 'PARSE_ERROR', raw: data });
            }
          });
        });

        req.on('error', (e) => {
          const isNetworkError = e.code === 'ECONNREFUSED' || e.code === 'ETIMEDOUT' || e.code === 'ENOTFOUND';
          if (isNetworkError && attempt < MAX_RETRIES - 1) {
            reject({ retryable: true, error: e.message, attempt });
          } else {
            resolve({ status: 'REQUEST_ERROR', error: e.message });
          }
        });

        req.on('timeout', () => {
          req.destroy();
          if (attempt < MAX_RETRIES - 1) {
            reject({ retryable: true, error: 'Timeout', attempt });
          } else {
            resolve({ status: 'TIMEOUT', error: 'Request timeout' });
          }
        });

        req.write(dataStr);
        req.end();
      });
    } catch (e) {
      if (e.retryable) {
        console.log(`[RETRY] Attempt ${e.attempt + 1}/${MAX_RETRIES}, waiting ${RETRY_DELAYS[e.attempt]}ms...`);
