// RISK-05: Risk Engine with Fee-Adjusted EV Gate
// Subtracts Kraken taker fee (0.26%) from EV calculation
// Prevents unprofitable micro-trades at small account size

const pred = $("Prediction Engine").first().json || {};
const strat = $("Strategy Scoring").first().json || {};

// Win probability (from Prediction Engine Bayesian or Strategy Scoring quorum)
const bayesianProb = (pred && pred.bayesianProb) || 0;
const strategyWinRate = (strat && strat.families) ?
  Object.values(strat.families || {})
    .filter(f => f && f.bull > 0)
    .length / Math.max(1, Object.keys(strat.families || {}).length)
  : 0.45;

// Use better of two estimates
const winRate = Math.max(bayesianProb || 0, strategyWinRate || 0.45);

// Risk-Reward Ratio (from volatility and support/resistance)
const atr = $("MTF Analysis").first().json.atr || 0;
const price = $("MTF Analysis").first().json.price || 80000;
const atrPct = atr / price;

// Estimate TP at 2.5x ATR, SL at 1x ATR
const tpPct = atrPct * 2.5;
const slPct = atrPct * 1.0;
const rr = tpPct / Math.max(slPct, 0.001);

// ============================================================================
// RISK-05: FEE-ADJUSTED EXPECTED VALUE
// ============================================================================
// Kraken taker fee: 0.26% (Pro account at current tier)
// Impact: For small account ($113), fees add up quickly
// Example: $5.65 trade with 0.26% fee = $0.015 cost
// At 10 trades/day with 1% avg return = 0.10 profit, 0.15 fee cost = net -0.05 (loss!)
//
// Solution: Only trade when EV > fee cost
// Formula: ev_adjusted = ev_theoretical - fee_impact

const KRAKEN_TAKER_FEE = 0.0026; // 0.26% Kraken Pro maker fee

// Expected Value (Kelly assumes linear payoff)
// EV = (WinRate * RR) - (1 - WinRate)
const ev = (winRate * rr) - (1 - winRate);

// Fee-adjusted EV: subtract the taker fee impact
// This assumes we pay fee on entry and exit (simplified model)
const ev_adjusted = ev - KRAKEN_TAKER_FEE;

console.log(`[RISK-05] EV: ${ev.toFixed(4)} → Adjusted: ${ev_adjusted.toFixed(4)} (fee impact: ${KRAKEN_TAKER_FEE.toFixed(4)})`);

// Kelly Fraction: f* = (WinRate * RR - (1 - WinRate)) / RR
// Use ADJUSTED EV to determine kelly
// Limit to 5% max exposure per trade
const rawKelly = ev_adjusted / Math.max(rr, 1);
const kellyFraction = Math.max(0, Math.min(rawKelly, 0.05));
const kellyPct = Math.round(kellyFraction * 100 * 10) / 10;

// ============================================================================
// FEE GATE OUTPUT
// ============================================================================
// Flag whether EV is profitable after fees
const feeGatePass = ev_adjusted > 0;
const feeGateStatus = feeGatePass ? 'PASS' : 'FAIL_INSUFFICIENT_EV_AFTER_FEES';

return [{json:{
