async function callDeepSeek() {
  return new Promise((resolve, reject) => {
    const payload = JSON.stringify({
      model: 'deepseek-chat',
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userPrompt }
      ],
      temperature: 0.2,
      max_tokens: 512
    });

    const req = https.request({
      hostname: 'api.deepseek.com',
      path: '/v1/chat/completions',
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${process.env.DEEPSEEK_API_KEY}`,
        'Content-Type': 'application/json',
        'Content-Length': Buffer.byteLength(payload)
      },
      timeout: 10000  // 10 second timeout for DeepSeek
    }, (res) => {
      let data = '';
      res.on('data', c => data += c);
      res.on('end', () => {
        try {
          const json = JSON.parse(data);
          const content = json.choices[0].message.content;

          // Parse the LLM's JSON response
          const parsed = JSON.parse(content.trim());

          // Validate required fields
          if (!parsed.direction || parsed.confidence === undefined) {
            reject(new Error('DeepSeek response missing direction or confidence'));
          }

          resolve({
            provider: 'deepseek',
            direction: parsed.direction,
            confidence: Math.max(0, Math.min(100, parseInt(parsed.confidence) || 0)),
            primary_signal: parsed.primary_signal || '',
            risk_flags: parsed.risk_flags || [],
            rationale: parsed.rationale || ''
          });
        } catch (e) {
          reject(new Error(`DeepSeek parse error: ${e.message.slice(0, 100)}`));
        }
      });
    });

    req.on('error', reject);
    req.on('timeout', () => {
      req.destroy();
      reject(new Error('DeepSeek timeout after 10s'));
    });
    req.write(payload);
    req.end();
  });
}

