        (reg.regime || '').toLowerCase(),
        'audit_log',
        orderStatus.toLowerCase()
      ]
    }
  ]
});

// Store to memory API
const storeResult = await new Promise((resolve) => {
  const opts = {
    hostname: 'super-agent-production.up.railway.app',
    path: '/memory/ingest',
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'X-Memory-Secret': process.env.MEMORY_API_SECRET,
      'Content-Length': Buffer.byteLength(payload)
    }
  };

  const req = https.request(opts, (res) => {
    let d = '';
    res.on('data', c => (d += c));
    res.on('end', () => {
      try {
        resolve(JSON.parse(d));
      } catch (e) {
        resolve({ stored: false, err: d.slice(0, 80) });
      }
    });
  });

  req.on('error', e => resolve({ stored: false, err: e.message }));
  req.setTimeout(8000, () => {
    req.destroy();
    resolve({ stored: false, err: 'timeout' });
  });

  req.write(payload);
  req.end();
});

